import type { DirectAnswerBlock, FaqItem, HowToStep } from "@/types/seo"

export interface LocaleContent {
  faqs: FaqItem[]
  aiAnswer: { question: string; answer: string }
  directAnswer: DirectAnswerBlock
  steps: HowToStep[]
  examples: Record<string, string>
}

export function getLocaleContent(
  localeSlug: string,
  toolSlug: string,
  locationName: string,
  currencySymbol: string,
  taxYear: string,
  vatName: string,
  vatRate: number,
): LocaleContent | undefined {
  const map = contentMap[localeSlug]
  if (!map) return undefined
  return map[toolSlug]?.(locationName, currencySymbol, taxYear, vatName, vatRate)
}

type ContentFactory = (
  loc: string,
  cur: string,
  ty: string,
  vn: string,
  vr: number,
) => LocaleContent

