      directAnswer: { question: `How much tax will I pay in ${loc} for ${ty}?`, answer: `Your tax in ${loc} includes Income Tax (progressive rates from 0-45% based on ${ty} brackets), the Medicare Levy (2%), and potentially the MLS. Use our free tax calculator with your income, deductions, and offsets to get an accurate estimate.`, snippetType: "paragraph" },
