      directAnswer: { question: `How much will my investments grow in ${loc}?`, answer: `Investment growth in ${loc} benefits from franking credits on Australian shares, 50% CGT discount for assets held 12+ months, and super's 15% earnings tax rate. Our compound interest calculator projects growth with these Australian tax advantages factored in.`, snippetType: "paragraph" },
