      directAnswer: { question: `How much take-home pay will I receive from my salary in ${loc}?`, answer: `Your take-home pay in ${loc} is your gross salary minus federal and provincial Income Tax, CPP contributions (5.95%), and EI premiums (1.66%). Use our free salary calculator for ${ty} rates to instantly compute your net pay for your province.`, snippetType: "paragraph" },
