      directAnswer: { question: `How much tax will I pay in ${loc} for ${ty}?`, answer: `Your tax in ${loc} includes federal Income Tax (15-33%), provincial Income Tax (varies by province), CPP (5.95%), and EI (1.66%). Tax credits like the Basic Personal Amount reduce your liability. Use our free tax calculator for your specific province.`, snippetType: "paragraph" },
