      directAnswer: { question: `What will my home loan EMI be in ${loc}?`, answer: `Your home loan EMI depends on the loan amount, interest rate, and tenure. Use our free EMI calculator to get an instant payment breakdown for current Indian interest rates, including tax benefits under Section 24 and Section 80C.`, snippetType: "paragraph" },
