      directAnswer: { question: `How much take-home pay will I receive in ${loc}?`, answer: `Your take-home pay in ${loc} is your gross salary minus PAYE Income Tax (10.5-39%), ACC earner levy (1.46%), KiwiSaver (3-10%), and student loan repayments if applicable. Use our free salary calculator for ${ty} rates.`, snippetType: "paragraph" },
