      directAnswer: { question: `How much tax will I pay in ${loc} for ${ty}?`, answer: `Your tax in ${loc} includes Income Tax via PAYE (10.5-39% brackets for ${ty}) plus the ACC earner levy (1.46%). Use our free tax calculator with your income and deductions for an accurate estimate.`, snippetType: "paragraph" },
