      directAnswer: { question: `What will my monthly mortgage payment be in ${loc}?`, answer: `Your monthly mortgage payment depends on the property price, deposit, interest rate, and loan term. ${loc} has no stamp duty, and KiwiSaver can help with your deposit. Use our mortgage calculator with current NZ rates for an instant payment estimate.`, snippetType: "paragraph" },
