      directAnswer: { question: `How much do I need to save for retirement in ${loc}?`, answer: `NZ Super provides a base pension from age 65. Aim for 20-25x your desired additional income in KiwiSaver. Our retirement calculator factors in NZ Super, KiwiSaver employer contributions, and the government contribution to estimate your target.`, snippetType: "paragraph" },
